import React, { Component } from 'react';
import { Button } from '@material-ui/core';
import { withStyles } from '@material-ui/core/styles';
import { ExpandLess, ExpandMore, ArrowForwardIos } from '@material-ui/icons';
import { isMobile } from 'react-device-detect';

import './InfoCard.css';
import { Link } from "react-scroll";

const styles = theme => ({
    nextCard: {
        borderRadius: 1000,
        border: '2px solid',
        '&:hover': {
            border: '2px solid',
        },
    },
    learnMore: {
        backgroundImage: 'linear-gradient(to bottom right, #f50057, #ff9a00)',
        color: 'white',
    }
});

class InfoCard extends Component {

    render() {

        const { classes } = this.props;

        return (
            <div className="info-card-container">
                <div className={
                    isMobile
                        ? "info-card-title-mobile"
                        : "info-card-title"
                }>
                    <div>{this.props.title}</div>
                </div>
                <div className="info-card-description">{this.props.description}</div>
                <div className="learn-more-container">
                    <Button
                        variant="contained"
                        onClick={this.props.onLearnMore}
                        className={classes.learnMore}
                    >
                        Learn More
                        <ArrowForwardIos fontSize="inherit" />
                    </Button>
                </div>
                <div className="info-card-next-container">
                    <div className="horizontal-line" />
                    {
                        this.props.transition
                            ?
                            <Link to={this.props.name} spy={true} smooth={true} offset={50} duration={500}>
                                <Button
                                    variant="outlined"
                                    color="secondary"
                                    className={classes.nextCard}
                                    onClick={this.props.onNext}
                                >
                                    <ExpandMore fontSize="large" />
                                </Button>
                            </Link>
                            :
                            <Link to={this.props.name} spy={true} smooth={true} offset={50} duration={500}>
                                <Button
                                    variant="outlined"
                                    color="secondary"
                                    className={classes.nextCard}
                                    onClick={this.props.onNext}
                                >
                                    <ExpandLess fontSize="large" />
                                </Button>
                            </Link>
                    }
                    <div className="horizontal-line" />
                </div>
            </div>
        )
    }
}

export default withStyles(styles)(InfoCard);